import javax.inject.Inject
import play.api.mvc.{Action, ControllerComponents}
import models.Order
import play.api.libs.cironio.QueryConfig
import play.api.libs.cirmongo.MongoDatabaseComponent

class OrderController @Inject()(cc: ControllerComponents,
                                val mongoDbComp: MongoDatabaseComponent)
  extends AbstractController(cc) {

  def getOrder(id: String): Action[AnyContent] = Action.async { implicit request =>
    val queryConfig = QueryConfig(model = Order, selector = Map("id" -> id), projection = Some(Map("orderStatus" -> 1)))
    mongoDbComp.mongodb().collection("orders").find(queryConfig).firstOption.flatMap(result => {
      result.map(order => Ok(Json.toJson(order))).orElse(NotFound)
    })
  }
}